<?php
if (!defined('ABSPATH')) exit;
class VH360_Giving_Funds { public static function get_funds($enabled_only=false){ global $wpdb; $t=VH360_Giving_Database::get_funds_table(); $where=$enabled_only?'WHERE enabled=1':''; return $wpdb->get_results("SELECT * FROM {$t} {$where} ORDER BY display_order ASC,label ASC"); } public static function get_fund($id){ global $wpdb; $t=VH360_Giving_Database::get_funds_table(); return $wpdb->get_row($wpdb->prepare("SELECT * FROM {$t} WHERE id=%d",$id)); } public static function save_fund($data){ global $wpdb; $t=VH360_Giving_Database::get_funds_table(); $now=current_time('mysql'); $row=array('fund_key'=>sanitize_key($data['fund_key']?:sanitize_title($data['label'])),'label'=>sanitize_text_field($data['label']),'description'=>sanitize_textarea_field($data['description']),'suggested_amounts'=>sanitize_text_field($data['suggested_amounts']),'default_amount'=>($data['default_amount']!==''?(float)$data['default_amount']:null),'enabled'=>!empty($data['enabled'])?1:0,'display_order'=>absint($data['display_order']),'updated_at'=>$now); if(!empty($data['id'])) return $wpdb->update($t,$row,array('id'=>absint($data['id']))); $row['created_at']=$now; return $wpdb->insert($t,$row); } }
